CREATE TABLE IF NOT EXISTS `account_group_rate_rules` (`id` INT AUTO_INCREMENT NOT NULL PRIMARY KEY, `account_id` INT NOT NULL, `group_key` TEXT NOT NULL, `ratio_override` DOUBLE NOT NULL, `created_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), `updated_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), FOREIGN KEY (`account_id`) REFERENCES `accounts`(`id`) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS `account_group_rates` (`id` INT AUTO_INCREMENT NOT NULL PRIMARY KEY, `account_id` INT NOT NULL, `group_key` TEXT NOT NULL, `group_name` TEXT NOT NULL, `description` TEXT, `ratio` DOUBLE NOT NULL, `last_synced_at` VARCHAR(191) NOT NULL, `created_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), `updated_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), FOREIGN KEY (`account_id`) REFERENCES `accounts`(`id`) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS `official_model_prices` (`id` INT AUTO_INCREMENT NOT NULL PRIMARY KEY, `provider_id` TEXT NOT NULL, `model_id` TEXT NOT NULL, `display_name` TEXT NOT NULL, `input_per_million_usd` DOUBLE, `output_per_million_usd` DOUBLE, `cache_read_per_million_usd` DOUBLE, `cache_write_per_million_usd` DOUBLE, `reasoning_per_million_usd` DOUBLE, `input_audio_per_million_usd` DOUBLE, `output_audio_per_million_usd` DOUBLE, `tiers_json` JSON, `source_updated_at` VARCHAR(191), `fetched_at` VARCHAR(191) NOT NULL);
CREATE TABLE IF NOT EXISTS `pricing_refresh_states` (`id` INT AUTO_INCREMENT NOT NULL PRIMARY KEY, `scope_type` TEXT NOT NULL, `scope_id` INT NOT NULL DEFAULT 0, `last_success_at` VARCHAR(191), `last_failure_at` VARCHAR(191), `last_failure_kind` TEXT, `failure_active` BOOLEAN NOT NULL DEFAULT false, `created_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), `updated_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')));
CREATE TABLE IF NOT EXISTS `site_model_price_rules` (`id` INT AUTO_INCREMENT NOT NULL PRIMARY KEY, `site_id` INT NOT NULL, `upstream_model_id` TEXT NOT NULL, `mapped_provider_id` TEXT, `mapped_model_id` TEXT, `mapping_mode` TEXT NOT NULL, `input_override_usd` DOUBLE, `output_override_usd` DOUBLE, `cache_read_override_usd` DOUBLE, `cache_write_override_usd` DOUBLE, `reasoning_override_usd` DOUBLE, `input_audio_override_usd` DOUBLE, `output_audio_override_usd` DOUBLE, `per_call_override_usd` DOUBLE, `created_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), `updated_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), FOREIGN KEY (`site_id`) REFERENCES `sites`(`id`) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS `site_model_prices` (`id` INT AUTO_INCREMENT NOT NULL PRIMARY KEY, `site_id` INT NOT NULL, `upstream_model_id` TEXT NOT NULL, `input_per_million_usd` DOUBLE, `output_per_million_usd` DOUBLE, `cache_read_per_million_usd` DOUBLE, `cache_write_per_million_usd` DOUBLE, `reasoning_per_million_usd` DOUBLE, `input_audio_per_million_usd` DOUBLE, `output_audio_per_million_usd` DOUBLE, `per_call_usd` DOUBLE, `pricing_semantics` TEXT NOT NULL, `raw_metadata_json` JSON, `fetched_at` VARCHAR(191) NOT NULL, FOREIGN KEY (`site_id`) REFERENCES `sites`(`id`) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS `site_pricing_profiles` (`site_id` INT NOT NULL PRIMARY KEY, `paid_cny` DOUBLE NOT NULL DEFAULT 1, `credited_usd` DOUBLE NOT NULL DEFAULT 1, `created_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), `updated_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), FOREIGN KEY (`site_id`) REFERENCES `sites`(`id`) ON DELETE CASCADE);
ALTER TABLE `accounts` DROP COLUMN `unit_cost`;
CREATE UNIQUE INDEX `account_group_rate_rules_account_group_unique` ON `account_group_rate_rules` (`account_id`, `group_key`(191));
CREATE UNIQUE INDEX `account_group_rates_account_group_unique` ON `account_group_rates` (`account_id`, `group_key`(191));
CREATE UNIQUE INDEX `official_model_prices_provider_model_unique` ON `official_model_prices` (`provider_id`(191), `model_id`(191));
CREATE UNIQUE INDEX `pricing_refresh_states_scope_unique` ON `pricing_refresh_states` (`scope_type`(191), `scope_id`);
CREATE UNIQUE INDEX `site_model_price_rules_site_model_unique` ON `site_model_price_rules` (`site_id`, `upstream_model_id`(191));
CREATE UNIQUE INDEX `site_model_prices_site_model_unique` ON `site_model_prices` (`site_id`, `upstream_model_id`(191));
CREATE INDEX `account_group_rate_rules_account_id_idx` ON `account_group_rate_rules` (`account_id`);
CREATE INDEX `account_group_rates_account_id_idx` ON `account_group_rates` (`account_id`);
CREATE INDEX `official_model_prices_model_id_idx` ON `official_model_prices` (`model_id`(191));
CREATE INDEX `site_model_price_rules_site_id_idx` ON `site_model_price_rules` (`site_id`);
CREATE INDEX `site_model_prices_site_id_idx` ON `site_model_prices` (`site_id`);
